  name: "Full Spec Overview",
  render: () => <div className="flex flex-col gap-10">
      {/* Primary row */}
      <div>
        <h3 className="text-base font-semibold text-gray-cool-900 mb-4">
          Primary
        </h3>
        <div className="flex items-center gap-4">
          <Button variant="primary">Button</Button>
          <Button variant="primary" size="icon" shape="square" aria-label="Add">
            <Plus className="size-4" />
          </Button>
          <Button variant="primary" size="icon" shape="circle" aria-label="Add">
            <Plus className="size-4" />
          </Button>
          <Button variant="primary" size="number" shape="square">
            1
          </Button>
          <Button variant="primary" size="number" shape="circle">
            1
          </Button>
          <SplitButton variant="primary" leadingIcon={<Plus className="size-4" />}>
            Button
          </SplitButton>
        </div>
      </div>

      {/* Secondary row */}
      <div>
        <h3 className="text-base font-semibold text-gray-cool-900 mb-4">
          Secondary
        </h3>
        <div className="flex items-center gap-4">
          <Button variant="secondary">Button</Button>
          <Button variant="secondary" size="icon" shape="square" aria-label="Add">
            <Plus className="size-4" />
          </Button>
          <Button variant="secondary" size="icon" shape="circle" aria-label="Add">
            <Plus className="size-4" />
          </Button>
          <Button variant="secondary" size="number" shape="square">
            1
          </Button>
          <Button variant="secondary" size="number" shape="circle">
            1
          </Button>
        </div>
      </div>

      {/* Tertiary row */}
      <div>
        <h3 className="text-base font-semibold text-gray-cool-900 mb-4">
          Tertiary
        </h3>
        <div className="flex items-center gap-4">
          <Button variant="tertiary">Button</Button>
          <Button variant="tertiary" size="icon" shape="square" aria-label="Add">
            <Plus className="size-4" />
          </Button>
          <Button variant="tertiary" size="icon" shape="circle" aria-label="Add">
            <Plus className="size-4" />
          </Button>
          <Button variant="tertiary" size="number" shape="square">
            1
          </Button>
          <Button variant="tertiary" size="number" shape="circle">
            1
          </Button>
        </div>
      </div>

      {/* Loading states */}
      <div>
        <h3 className="text-base font-semibold text-gray-cool-900 mb-4">
          Loading
        </h3>
        <div className="flex items-center gap-4">
          <Button variant="primary" loading>
            Button
          </Button>
          <Button variant="secondary" loading>
            Button
          </Button>
          <Button variant="tertiary" loading>
            Button
          </Button>
        </div>
      </div>

      {/* Disabled states */}
      <div>
        <h3 className="text-base font-semibold text-gray-cool-900 mb-4">
          Disabled
        </h3>
        <div className="flex items-center gap-4">
          <Button variant="primary" disabled>
            Button
          </Button>
          <Button variant="secondary" disabled>
            Button
          </Button>
          <Button variant="tertiary" disabled>
            Button
          </Button>
        </div>
      </div>
    </div>
